  ('elementary-8b44517b-moex-00001', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-b3f42868', 'sub-elementary-8b44517b-01', NULL, 'single_choice', '目前各國衡量一國的經濟成長常會使用國民所得的數據來顯示，但國民所得的數據只是整體與平均經濟 狀況表象，下列何種曲線可以呈現國民所得分配不均程度？', '["恩格爾曲線", "菲利浦曲線", "勞倫斯曲線", "生產可能曲線"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00002', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-b3f42868', 'sub-elementary-8b44517b-01', NULL, 'single_choice', '某國生產兩種產品（X與Y，分別表示為水平軸與垂直軸），其凹向原點的生產可能曲線上，由左上往右 下依序為A、B、C三個點，下列敘述何者正確？', '["就生產效率的大小而言，A＞B＞C", "多生產一單位X的機會成本為A＞B＞C", "就生產效率的大小而言，A＝B＝C", "多生產一單位Y的機會成本為A＝B＝C"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00003', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-b3f42868', 'sub-elementary-8b44517b-01', NULL, 'single_choice', '跨太平洋夥伴全面進步協定（CPTPP）旨在促進泛太平洋國家間的貿易自由化。依其宗旨判斷，參與此種 經濟合作組織的國家，會產生下列何種現象？', '["勞動要素可自由流動", "各國間實施關稅保護", "共同發行統一的貨幣", "市場上商品種類增加"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00004', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-b3f42868', 'sub-elementary-8b44517b-01', NULL, 'single_choice', '對社會而言，下列那一種財貨或服務的機會成本最低？', '["政府提供的免費服務", "不具相對稀少性的物品", "準備拿來當作肥料的雞糞", "無法提升消費者效用的物品"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00005', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-b3f42868', 'sub-elementary-8b44517b-01', NULL, 'single_choice', '市場上的生產者與消費者會隨著產品價格的上漲或下跌，不斷地調整其生產或消費行為，最後會達到市場 均衡。下列針對此市場均衡的相關敘述，何者正確？', '["無謂損失等於零", "生產者剩餘達到最小值", "社會總剩餘等於消費者剩餘", "社會福利等於社會總效益加社會總成本"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
